func TestGetOriginal(t *testing.T) {
	testCases := []struct {
		name     string
		sentence string
		words    []string
	}{
		{
			name:     "Regular sentence",
			sentence: "This is a test sentence.",
			words:    []string{"this", "is", "a", "test", "sentence"},
		},
		{
			name:     "Empty sentence",
			sentence: "",
			words:    []string{},
		},
		{
			name:     "Special characters",
			sentence: "Hello, world! How are you?",
			words:    []string{"hello", "world", "how", "are", "you"},
		},
		{
			name:     "Unicode characters",
			sentence: "こんにちは世界",
			words:    []string{"こんにちは", "世界"},
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			parsedSentence := ParsedSentence{
				original: tc.sentence,
				words:    tc.words,
			}

			result := parsedSentence.GetOriginal()

			if result != tc.sentence {
				t.Errorf("Expected original sentence to be %q, got %q", tc.sentence, result)
			}
		})
	}
}

