package textrank

import (
	"testing"
)

func TestAddRelation(t *testing.T) {
	// Test case 1: related_word_id is -1
	t.Run("RelatedWordIdIsNegativeOne", func(t *testing.T) {
		relation := &Relation{
			Node: make(map[int]map[int]Score),
		}

		// Call AddRelation with related_word_id = -1
		relation.AddRelation(1, -1, 10)

		// Verify that no relation was added
		if len(relation.Node) != 0 {
			t.Errorf("Expected no relations to be created, got %d", len(relation.Node))
		}
	})

	// Test case 2: Update existing relation
	t.Run("UpdateExistingRelation", func(t *testing.T) {
		relation := &Relation{
			Node: make(map[int]map[int]Score),
		}

		// Setup an existing relation
		relation.Node[2] = make(map[int]Score)
		relation.Node[2][1] = Score{
			Qty:         1,
			Weight:      0,
			SentenceIDs: []int{5},
		}

		// Call AddRelation
		relation.AddRelation(1, 2, 10)

		// Verify that the relation was updated
		if score, ok := relation.Node[2][1]; !ok {
			t.Error("Expected relation to be updated, but it doesn't exist")
		} else {
			if score.Qty != 2 {
				t.Errorf("Expected Qty to be 2, got %d", score.Qty)
			}
			if len(score.SentenceIDs) != 2 || score.SentenceIDs[1] != 10 {
				t.Errorf("Expected SentenceIDs to contain [5, 10], got %v", score.SentenceIDs)
			}
		}
	})

	// Test case 3: Extend relation
	t.Run("ExtendRelation", func(t *testing.T) {
		relation := &Relation{
			Node: make(map[int]map[int]Score),
		}

		// Setup an existing relation node for word_id
		relation.Node[1] = make(map[int]Score)

		// Call AddRelation
		relation.AddRelation(1, 2, 10)

		// Verify that the relation was extended
		if score, ok := relation.Node[1][2]; !ok {
			t.Error("Expected relation to be extended, but it doesn't exist")
		} else {
			if score.Qty != 1 {
				t.Errorf("Expected Qty to be 1, got %d", score.Qty)
			}
			if len(score.SentenceIDs) != 1 || score.SentenceIDs[0] != 10 {
				t.Errorf("Expected SentenceIDs to contain [10], got %v", score.SentenceIDs)
			}
		}
	})

	// Test case 4: Create new relation
	t.Run("CreateNewRelation", func(t *testing.T) {
		relation := &Relation{
			Node: make(map[int]map[int]Score),
		}

		// Call AddRelation
		relation.AddRelation(1, 2, 10)

		// Verify that the relation was created
		if _, ok := relation.Node[1]; !ok {
			t.Error("Expected relation[1] to be created, but it doesn't exist")
		}

		if score, ok := relation.Node[1][2]; !ok {
			t.Error("Expected relation[1][2] to be created, but it doesn't exist")
		} else {
			if score.Qty != 1 {
				t.Errorf("Expected Qty to be 1, got %d", score.Qty)
			}
			if len(score.SentenceIDs) != 1 || score.SentenceIDs[0] != 10 {
				t.Errorf("Expected SentenceIDs to contain [10], got %v", score.SentenceIDs)
			}
		}
	})

	// Test case 5: Recursive relation update (swap word_id and related_word_id)
	t.Run("RecursiveRelationUpdate", func(t *testing.T) {
		relation := &Relation{
			Node: make(map[int]map[int]Score),
		}

		// Setup an existing relation but with reversed ids
		relation.Node[1] = make(map[int]Score)
		relation.Node[1][2] = Score{
			Qty:         1,
			Weight:      0,
			SentenceIDs: []int{5},
		}

		// Call AddRelation (note the order is reversed compared to the stored relation)
		relation.AddRelation(2, 1, 10)

		// Verify that the relation was updated
		if score, ok := relation.Node[1][2]; !ok {
			t.Error("Expected relation to be updated, but it doesn't exist")
		} else {
			if score.Qty != 2 {
				t.Errorf("Expected Qty to be 2, got %d", score.Qty)
			}
			if len(score.SentenceIDs) != 2 || score.SentenceIDs[1] != 10 {
				t.Errorf("Expected SentenceIDs to contain [5, 10], got %v", score.SentenceIDs)
			}
		}
	})

	// Test case 6: Recursive relation extend (swap word_id and related_word_id)
	t.Run("RecursiveRelationExtend", func(t *testing.T) {
		relation := &Relation{
			Node: make(map[int]map[int]Score),
		}

		// Setup an existing node for related_word_id
		relation.Node[2] = make(map[int]Score)

