package textrank

import (
	"testing"
)

// MockLanguage implements the Language interface for testing purposes
type MockLanguage struct {
	stopWords     map[string]bool
	rootWordMaps  map[string]string
	activeLanguage string
}

func NewMockLanguage() *MockLanguage {
	return &MockLanguage{
		stopWords:     make(map[string]bool),
		rootWordMaps:  make(map[string]string),
		activeLanguage: "en",
	}
}

func (m *MockLanguage) IsStopWord(word string) bool {
	return m.stopWords[word]
}

func (m *MockLanguage) FindRootWord(word string) (bool, string) {
	root, found := m.rootWordMaps[word]
	if found {
		return true, root
	}
	return false, ""
}

func (m *MockLanguage) SetWords(code string, words []string) {
	for _, word := range words {
		m.stopWords[word] = true
	}
}

func (m *MockLanguage) SetActiveLanguage(code string) {
	m.activeLanguage = code
}

// TestTextToRankBasic tests the basic functionality of TextToRank
func TestTextToRankBasic(t *testing.T) {
	// Create a mock language
	lang := NewMockLanguage()
	lang.stopWords["the"] = true
	lang.stopWords["a"] = true
	lang.rootWordMaps["running"] = "run"

	// Create a parsed sentence
	sentence := ParsedSentence{
		original: "This is a test sentence with running words",
		words: []string{"This", "is", "a", "test", "sentence", "with", "running", "words"},
	}

	// Create a new rank object
	ranks := &Rank{
		Max:         0.0,
		Min:         0.0,
		Relation:    Relation{Node: make(map[int]map[int]Score)},
		SentenceMap: make(map[int]string),
		Words:       make(map[int]*Word),
		WordValID:   make(map[string]int),
	}

	// Call the function to test
	TextToRank(sentence, lang, ranks)

	// Assert that the sentence was added to the sentence map
	if len(ranks.SentenceMap) != 1 {
		t.Errorf("Expected 1 sentence in the sentence map, got %d", len(ranks.SentenceMap))
	}

	// Assert that the sentence content matches
	if ranks.SentenceMap[0] != sentence.original {
		t.Errorf("Expected sentence original text to be '%s', got '%s'", 
			sentence.original, ranks.SentenceMap[0])
	}

	// Assert that words were added (excluding stop words)
	expectedNonStopWords := 7 // This, is, test, sentence, with, run (from running), words
	if len(ranks.Words) != expectedNonStopWords {
		t.Errorf("Expected %d words to be added, got %d", expectedNonStopWords, len(ranks.Words))
	}

	// Check that "run" exists (transformed from "running")
	if _, exists := ranks.WordValID["run"]; !exists {
		t.Errorf("Expected 'run' to be in the word map (transformed from 'running')")
	}

	// Check that stop words are not in the map
	if _, exists := ranks.WordValID["a"]; exists {
		t.Errorf("Stop word 'a' should not be in the word map")
	}
}

// TestTextToRankEmptyWords tests the behavior with empty word list
func TestTextToRankEmptyWords(t *testing.T) {
	// Create a mock language
	lang := NewMockLanguage()

	// Create a parsed sentence with no words
	sentence := ParsedSentence{
		original: "Empty words test",
		words: []string{},
	}

	// Create a new rank object
	ranks := &Rank{
		Max:         0.0,
		Min:         0.0,
		Relation:    Relation{Node: make(map[int]map[int]Score)},
		SentenceMap: make(map[int]string),
		Words:       make(map[int]*Word),
		WordValID:   make(map[string]int),
	}

	// Call the function to test
	TextToRank(sentence, lang, ranks)

	// Assert that the sentence was still added to the sentence map
	if len(ranks.SentenceMap) != 1 {
		t.Errorf("Expected 1 sentence in the sentence map, got %d", len(ranks.SentenceMap))
	}

	// Assert that no words were added
	if len(ranks.Words) != 0 {
		t.Errorf("Expected 0 words to be added, got %d", len(ranks.Words))
	}
}

// TestTextToRankAllStopWords tests the behavior when all words are stop words
func TestTextToRankAllStopWords(t *testing.T) {
	// Create a mock language where all words are stop words
	lang := NewMockLanguage()
	lang.stopWords["the"] = true
	lang.stopWords["a"] = true
	lang.stopWords["is"] = true

	// Create a parsed sentence with only stop words
	sentence := ParsedSentence{
		original: "the a is",
